const labels = [];
for (let row = 1; row <= 7; row += 1) {
  for (let col = 1; col <= 3; col += 1) {
    labels.push({ row, col, index: labels.length + 1 });
  }
}

const renderLabel = (label) => `
  <div class="label">
    <div class="corner tl"></div>
    <div class="corner tr"></div>
    <div class="corner bl"></div>
    <div class="corner br"></div>
    <div class="crosshair"></div>
    <div class="grid-label">R${label.row} C${label.col}</div>
    <div class="measure top">${label.index}</div>
    <div class="measure left">${label.row}.${label.col}</div>
  </div>`;

const html = `<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="utf-8">
  <title>J8160 Calibration</title>
  <style>
    @page {
      size: A4;
      margin: 0;
    }
    * {
      box-sizing: border-box;
    }
    html, body {
      margin: 0;
      padding: 0;
      width: 210mm;
      background: #fff;
    }
    body {
      font-family: Arial, Helvetica, sans-serif;
      color: #000;
      -webkit-print-color-adjust: exact;
      print-color-adjust: exact;
    }
    .sheet {
      width: 210mm;
      height: 297mm;
      padding: 14.7mm 0 0 4.5mm;
      display: grid;
      grid-template-columns: repeat(3, 63.5mm);
      grid-template-rows: repeat(7, 38.33mm);
      column-gap: 2.54mm;
      row-gap: 0;
    }
    .label {
      position: relative;
      width: 63.5mm;
      height: 38.1mm;
      border: 0.2mm solid rgba(0, 0, 255, 0.55);
      border-radius: 3mm;
      overflow: hidden;
    }
    .grid-label {
      position: absolute;
      top: 2.8mm;
      left: 3mm;
      font-size: 11pt;
      font-weight: 700;
      color: rgba(220, 0, 0, 0.85);
    }
    .measure {
      position: absolute;
      font-size: 7pt;
      color: rgba(0, 0, 0, 0.75);
      background: rgba(255, 255, 255, 0.7);
      padding: 0.2mm 0.6mm;
      border-radius: 1mm;
    }
    .measure.top {
      top: 2.8mm;
      right: 3mm;
    }
    .measure.left {
      left: 3mm;
      bottom: 2.8mm;
    }
    .crosshair {
      position: absolute;
      left: 50%;
      top: 50%;
      width: 10mm;
      height: 10mm;
      transform: translate(-50%, -50%);
    }
    .crosshair::before,
    .crosshair::after {
      content: "";
      position: absolute;
      background: rgba(0, 150, 0, 0.55);
    }
    .crosshair::before {
      left: 50%;
      top: 0;
      width: 0.2mm;
      height: 100%;
      transform: translateX(-50%);
    }
    .crosshair::after {
      top: 50%;
      left: 0;
      height: 0.2mm;
      width: 100%;
      transform: translateY(-50%);
    }
    .corner {
      position: absolute;
      width: 6mm;
      height: 6mm;
      border-color: rgba(0, 0, 255, 0.55);
      border-style: solid;
    }
    .corner.tl {
      top: 1.6mm;
      left: 1.6mm;
      border-width: 0.25mm 0 0 0.25mm;
    }
    .corner.tr {
      top: 1.6mm;
      right: 1.6mm;
      border-width: 0.25mm 0.25mm 0 0;
    }
    .corner.bl {
      bottom: 1.6mm;
      left: 1.6mm;
      border-width: 0 0 0.25mm 0.25mm;
    }
    .corner.br {
      bottom: 1.6mm;
      right: 1.6mm;
      border-width: 0 0.25mm 0.25mm 0;
    }
  </style>
</head>
<body>
  <section class="sheet">${labels.map(renderLabel).join('')}</section>
</body>
</html>`;

return [{
  json: {
    label_count: labels.length,
    page_count: 1
  },
  binary: {
    data: {
      data: Buffer.from(html, 'utf8').toString('base64'),
      mimeType: 'text/html',
      fileName: 'index.html',
      fileExtension: 'html'
    }
  }
}];

const item = $input.first();
const binary = item.binary?.data;
if (!binary?.data) {
  throw new Error('Gotenberg did not return a PDF binary payload.');
}
const generatedAt = new Date().toISOString();
return [{
  json: {
    ...(item.json ?? {}),
    generated_at: generatedAt
  },
  binary: {
    data: {
      ...binary,
      mimeType: 'application/pdf',
      fileName: `j8160-calibration-${generatedAt.replace(/[:.]/g, '-')}.pdf`,
      fileExtension: 'pdf'
    }
  }
}];
